import java.util.*; public class StringTrimmer{static String trimText(String s){int st=0,en=s.length()-1;while(st<s.length()&&s.charAt(st)==' ')st++;while(en>=0&&s.charAt(en)==' ')en--;return s.substring(st,en+1);}public static void main(String[] a){Scanner sc=new Scanner(System.in);String s=sc.nextLine();System.out.println(trimText(s));System.out.println(trimText(s).equals(s.trim()));}}